class CircularFlowDelegate extends FlowDelegate {
  final double progress;
  CircularFlowDelegate(this.progress);

  @override
  void paintChildren(FlowPaintingContext context) {
    final radius = context.size.shortestSide / 2;
    for (int i = 0; i < context.childCount; i++) {
      final angle = i * 2 * pi / context.childCount;
      context.paintChild(i, transform: Matrix4.translationValues(
        radius * cos(angle) * progress,
        radius * sin(angle) * progress, 0));
    }
  }
}
